/**
 * Multi-Agent Orchestration
 *
 * Demonstrates how to build a multi-agent system using the Pi SDK.
 * A coordinator agent delegates tasks to specialized agents, collects
 * results, and synthesizes a final response.
 *
 * Patterns demonstrated:
 *   1. Coordinator + Specialist agents with different roles
 *   2. Context passing between agents (output → input)
 *   3. Parallel specialist execution
 *   4. Streaming from multiple agents simultaneously
 *   5. Role-based tool configuration (read-only vs full access)
 *   6. Result aggregation and synthesis
 *
 * Usage:
 *   npx tsx examples/sdk/14-multi-agent.ts
 *
 * Architecture:
 *
 *   User Prompt
 *       │
 *       ▼
 *   ┌───────────┐
 *   │ Coordinator│  Decides what to delegate, synthesizes final answer
 *   └─────┬─────┘
 *         │
 *   ┌─────┼─────────────┐
 *   │     │              │
 *   ▼     ▼              ▼
 * ┌─────┐ ┌─────┐  ┌─────────┐
 * │Scout│ │Coder│  │Reviewer │  Each has own tools, prompt, session
 * └─────┘ └─────┘  └─────────┘
 *   │     │              │
 *   └─────┼──────────────┘
 *         │
 *         ▼
 *   Coordinator synthesizes
 *         │
 *         ▼
 *   Final Response to User
 */

import { getModel } from "@earendil-works/pi-ai";
import {
	AuthStorage,
	createAgentSession,
	DefaultResourceLoader,
	getAgentDir,
	ModelRegistry,
	SessionManager,
} from "@earendil-works/pi-coding-agent";

// ============================================================================
// Types
// ============================================================================

interface AgentRole {
	name: string;
	systemPrompt: string;
	/** Built-in tool names this agent can use */
	tools: string[];
	/** Model override (provider/id format) */
	model?: string;
}

interface AgentResult {
	role: string;
	output: string;
	/** Whether the agent completed successfully */
	success: boolean;
	/** Error message if failed */
	error?: string;
}

interface OrchestrationPlan {
	/** Steps to execute, each referencing a role name and task */
	steps: Array<{
		role: string;
		task: string;
		/** If true, run in parallel with other parallel steps */
		parallel?: boolean;
	}>;
}

// ============================================================================
// Agent Roles — Each specialist has its own prompt and tool set
// ============================================================================

const ROLES: Record<string, AgentRole> = {
	scout: {
		name: "Scout",
		systemPrompt: `You are a fast codebase reconnaissance agent.
Your job: investigate the codebase and return compressed, structured findings.

Strategy:
1. Use grep/find to locate relevant code
2. Read key sections (not entire files)
3. Identify types, interfaces, key functions
4. Note dependencies between files

Output format:

## Files Found
List with exact line ranges.

## Key Types/Functions
Critical code snippets.

## Architecture
How the pieces connect.

Be thorough but concise. Your output feeds into a planner who hasn't seen the code.`,
		tools: ["read", "bash"],
		model: "anthropic/claude-haiku-4-5",
	},

	coder: {
		name: "Coder",
		systemPrompt: `You are an implementation specialist.
You receive a plan with specific steps and execute them.

Strategy:
1. Read the files mentioned in the plan
2. Make the changes described
3. Verify your changes compile/run
4. Report what you changed

Output format:

## Changes Made
- file.ts: what changed

## Verification
What you checked to confirm it works.

Be precise. Follow the plan exactly. Don't add unrequested changes.`,
		tools: ["read", "bash", "edit", "write"],
		model: "anthropic/claude-sonnet-4-5",
	},

	reviewer: {
		name: "Reviewer",
		systemPrompt: `You are a senior code reviewer.
You analyze code for quality, security, and maintainability.

Strategy:
1. Read the changed files
2. Check for bugs, security issues, code smells
3. Verify tests pass
4. Suggest improvements

Output format:

## Critical (must fix)
Issues that block merge.

## Warnings (should fix)
Issues that should be addressed.

## Suggestions (nice to have)
Improvement ideas.

## Summary
Overall assessment in 2-3 sentences.

Be specific with file paths and line numbers.`,
		tools: ["read", "bash"],
		model: "anthropic/claude-sonnet-4-5",
	},

	planner: {
		name: "Planner",
		systemPrompt: `You are an implementation planner.
You receive context (from a scout) and requirements, then produce a clear plan.

You must NOT make any changes. Only read, analyze, and plan.

Output format:

## Goal
One sentence summary.

## Plan
Numbered steps, each small and actionable.

## Files to Modify
- path/to/file.ts - what changes

## New Files (if any)
- path/to/new.ts - purpose

## Risks
Anything to watch out for.

Keep the plan concrete. A coder will execute it verbatim.`,
		tools: ["read", "bash"],
		model: "anthropic/claude-sonnet-4-5",
	},
};

// ============================================================================
// Helper: Create an agent session for a specific role
// ============================================================================

async function createRoleAgent(role: AgentRole, cwd: string) {
	const authStorage = AuthStorage.create();
	const modelRegistry = ModelRegistry.create(authStorage);

	// Find the model
	let model;
	if (role.model) {
		const [provider, id] = role.model.split("/");
		model = getModel(provider, id);
	}

	const loader = new DefaultResourceLoader({
		cwd,
		agentDir: getAgentDir(),
		// Each role gets its own system prompt
		systemPromptOverride: () => role.systemPrompt,
		appendSystemPromptOverride: () => [],
	});
	await loader.reload();

	const { session } = await createAgentSession({
		model,
		tools: role.tools,
		resourceLoader: loader,
		sessionManager: SessionManager.inMemory(),
		authStorage,
		modelRegistry,
	});

	return session;
}

// ============================================================================
// Helper: Run a prompt and collect the full output
// ============================================================================

async function runAgent(
	session: Awaited<ReturnType<typeof createRoleAgent>>,
	roleName: string,
	prompt: string,
): Promise<AgentResult> {
	return new Promise((resolve) => {
		let output = "";

		const unsubscribe = session.subscribe((event) => {
			if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
				output += event.assistantMessageEvent.delta;
			}
		});

		session
			.prompt(prompt)
			.then(() => {
				unsubscribe();
				resolve({ role: roleName, output, success: true });
			})
			.catch((error) => {
				unsubscribe();
				resolve({
					role: roleName,
					output,
					success: false,
					error: error instanceof Error ? error.message : String(error),
				});
			});
	});
}

// ============================================================================
// Helper: Stream output with role prefix (for live monitoring)
// ============================================================================

function createStreamLogger(roleName: string) {
	let buffer = "";
	const prefix = `\x1b[36m[${roleName}]\x1b[0m `;

	return {
		onToken(delta: string) {
			const lines = delta.split("\n");
			for (let i = 0; i < lines.length; i++) {
				if (i > 0) process.stdout.write("\n" + prefix);
				process.stdout.write(lines[i]);
			}
		},
	};
}

// ============================================================================
// Pattern 1: Sequential Pipeline
//
// Agent A → Agent B → Agent C
// Each agent's output becomes the next agent's input
// ============================================================================

async function sequentialPipeline(cwd: string) {
	console.log("\n═══════════════════════════════════════════════════");
	console.log("  Pattern 1: Sequential Pipeline");
	console.log("  scout → planner → coder → reviewer");
	console.log("═══════════════════════════════════════════════════\n");

	const task = "Add error handling to the main entry point";

	// Step 1: Scout investigates
	console.log("\x1b[33m▶ Step 1/4: Scout investigating...\x1b[0m");
	const scoutSession = await createRoleAgent(ROLES.scout, cwd);
	const scout = await runAgent(scoutSession, "scout", `Investigate the codebase for: ${task}`);
	scoutSession.dispose();
	console.log(`\n\x1b[32m✓ Scout complete\x1b[0m (${scout.output.length} chars)\n`);

	// Step 2: Planner creates plan using scout's findings
	console.log("\x1b[33m▶ Step 2/4: Planner creating plan...\x1b[0m");
	const plannerSession = await createRoleAgent(ROLES.planner, cwd);
	const planner = await runAgent(
		plannerSession,
		"planner",
		`Task: ${task}\n\nFindings from scout:\n${scout.output}`,
	);
	plannerSession.dispose();
	console.log(`\n\x1b[32m✓ Planner complete\x1b[0m (${planner.output.length} chars)\n`);

	// Step 3: Coder implements the plan
	console.log("\x1b[33m▶ Step 3/4: Coder implementing...\x1b[0m");
	const coderSession = await createRoleAgent(ROLES.coder, cwd);
	const coder = await runAgent(
		coderSession,
		"coder",
		`Implement this plan:\n${planner.output}`,
	);
	coderSession.dispose();
	console.log(`\n\x1b[32m✓ Coder complete\x1b[0m (${coder.output.length} chars)\n`);

	// Step 4: Reviewer checks the implementation
	console.log("\x1b[33m▶ Step 4/4: Reviewer checking...\x1b[0m");
	const reviewerSession = await createRoleAgent(ROLES.reviewer, cwd);
	const reviewer = await runAgent(
		reviewerSession,
		"reviewer",
		`Review these changes:\n${coder.output}\n\nOriginal task: ${task}`,
	);
	reviewerSession.dispose();
	console.log(`\n\x1b[32m✓ Reviewer complete\x1b[0m (${reviewer.output.length} chars)\n`);

	return { scout, planner, coder, reviewer };
}

// ============================================================================
// Pattern 2: Fan-Out / Fan-In (Parallel Specialists)
//
// Coordinator dispatches to multiple agents simultaneously,
// then collects and merges results
// ============================================================================

async function parallelFanOut(cwd: string) {
	console.log("\n═══════════════════════════════════════════════════");
	console.log("  Pattern 2: Parallel Fan-Out / Fan-In");
	console.log("  Two scouts run simultaneously → merge findings");
	console.log("═══════════════════════════════════════════════════\n");

	// Create two scout sessions for parallel investigation
	const [scoutA, scoutB] = await Promise.all([
		createRoleAgent(ROLES.scout, cwd),
		createRoleAgent(ROLES.scout, cwd),
	]);

	// Dispatch both simultaneously
	console.log("\x1b[33m▶ Dispatching 2 scouts in parallel...\x1b[0m\n");

	const [resultA, resultB] = await Promise.all([
		runAgent(scoutA, "scout-auth", "Find all authentication and authorization code. Focus on login, sessions, tokens."),
		runAgent(scoutB, "scout-api", "Find all API route handlers and middleware. Focus on endpoints and request flow."),
	]);

	scoutA.dispose();
	scoutB.dispose();

	console.log("\n\x1b[32m✓ Both scouts complete\x1b[0m");
	console.log(`  scout-auth: ${resultA.output.length} chars`);
	console.log(`  scout-api:  ${resultB.output.length} chars\n`);

	// Merge findings
	const mergedFindings = `
# Merged Codebase Analysis

## Authentication Findings
${resultA.output}

## API Route Findings
${resultB.output}
`;

	return mergedFindings;
}

// ============================================================================
// Pattern 3: Coordinator Agent (Orchestrator Pattern)
//
// A coordinator agent decides what to delegate, how to split work,
// and synthesizes the final answer. The coordinator runs as a real
// agent session with custom tools that spawn specialists.
// ============================================================================

async function coordinatorPattern(cwd: string) {
	console.log("\n═══════════════════════════════════════════════════");
	console.log("  Pattern 3: Coordinator Agent");
	console.log("  Coordinator analyzes task, delegates, synthesizes");
	console.log("═══════════════════════════════════════════════════\n");

	const task = "Review the project structure and suggest improvements";

	// The coordinator uses all tools and decides how to break down the task
	const coordinatorSession = await createRoleAgent(
		{
			name: "Coordinator",
			systemPrompt: `You are a task coordinator. When given a task, you break it down and delegate to specialists.

Available specialists:
- scout: Investigates codebase (read-only, fast)
- reviewer: Code review (read-only, thorough)

For this task, output a JSON plan (no other text) with this exact format:
{
  "steps": [
    { "role": "scout", "task": "description of what to investigate" },
    { "role": "reviewer", "task": "description of what to review" }
  ]
}

Then after receiving results, synthesize a final recommendation.`,
			tools: ["read", "bash"],
		},
		cwd,
	);

	// Coordinator analyzes the task
	console.log("\x1b[33m▶ Coordinator analyzing task...\x1b[0m\n");

	let planJson = "";
	const unsubscribe = coordinatorSession.subscribe((event) => {
		if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
			const delta = event.assistantMessageEvent.delta;
			planJson += delta;
			process.stdout.write(delta);
		}
	});

	await coordinatorSession.prompt(
		`Task: ${task}\n\nCurrent directory: ${cwd}\n\nCreate a delegation plan (JSON only, no markdown fences).`,
	);
	unsubscribe();

	// Parse the plan (extract JSON from response)
	let plan: OrchestrationPlan;
	try {
		const jsonMatch = planJson.match(/\{[\s\S]*\}/);
		if (jsonMatch) {
			plan = JSON.parse(jsonMatch[0]) as OrchestrationPlan;
		} else {
			throw new Error("No JSON found in coordinator response");
		}
	} catch {
		// Fallback plan if coordinator doesn't produce valid JSON
		console.log("\n\x1b[33m⚠ Could not parse coordinator plan, using fallback\x1b[0m");
		plan = {
			steps: [
				{ role: "scout", task: `Investigate the project structure: ${task}` },
				{ role: "reviewer", task: `Review the project for improvements: ${task}` },
			],
		};
	}

	coordinatorSession.dispose();

	console.log(`\n\n\x1b[32m✓ Plan created: ${plan.steps.length} steps\x1b[0m\n`);

	// Execute specialists in parallel based on the plan
	const specialistResults: AgentResult[] = [];

	// Group steps by parallel flag
	const parallelSteps = plan.steps.filter((s) => s.parallel !== false);
	const sequentialSteps = plan.steps.filter((s) => s.parallel === false);

	// Run parallel steps simultaneously
	if (parallelSteps.length > 0) {
		console.log(`\x1b[33m▶ Running ${parallelSteps.length} specialists in parallel...\x1b[0m\n`);

		const parallelResults = await Promise.all(
			parallelSteps.map(async (step) => {
				const role = ROLES[step.role];
				if (!role) {
					return { role: step.role, output: "", success: false, error: `Unknown role: ${step.role}` };
				}
				const session = await createRoleAgent(role, cwd);
				const result = await runAgent(session, step.role, step.task);
				session.dispose();
				return result;
			}),
		);

		specialistResults.push(...parallelResults);
	}

	// Run sequential steps
	for (const step of sequentialSteps) {
		const role = ROLES[step.role];
		if (!role) {
			specialistResults.push({ role: step.role, output: "", success: false, error: `Unknown role: ${step.role}` });
			continue;
		}
		console.log(`\x1b[33m▶ ${role.name} working...\x1b[0m`);
		const session = await createRoleAgent(role, cwd);
		const result = await runAgent(session, step.role, step.task);
		session.dispose();
		specialistResults.push(result);
		console.log(`\x1b[32m✓ ${role.name} complete\x1b[0m`);
	}

	return specialistResults;
}

// ============================================================================
// Pattern 4: Debate / Adversarial Review
//
// Two agents with opposing views argue a position,
// then a judge synthesizes the best answer
// ============================================================================

async function debatePattern(cwd: string) {
	console.log("\n═══════════════════════════════════════════════════");
	console.log("  Pattern 4: Adversarial Debate");
	console.log("  Advocate vs Devil's Advocate → Judge decides");
	console.log("═══════════════════════════════════════════════════\n");

	const topic = "Should this project use a monorepo or polyrepo structure?";

	const advocate = {
		name: "Advocate",
		systemPrompt: `You are an advocate arguing FOR a position. Make the strongest case possible.
Be specific, use evidence, and anticipate counterarguments.
Output a concise argument (max 500 words).`,
		tools: ["read", "bash"],
	};

	const devil = {
		name: "DevilsAdvocate",
		systemPrompt: `You are a devil's advocate arguing AGAINST a position. Find every weakness.
Be specific, identify risks, and challenge assumptions.
Output a concise counter-argument (max 500 words).`,
		tools: ["read", "bash"],
	};

	const judge = {
		name: "Judge",
		systemPrompt: `You are an impartial judge. You receive arguments from both sides and produce a balanced verdict.
Consider: evidence quality, practical implications, and risk.
Output a clear recommendation with reasoning.`,
		tools: [],
	};

	// Both sides argue simultaneously
	console.log("\x1b[33m▶ Both sides presenting arguments...\x1b[0m\n");

	const [advocateSession, devilSession] = await Promise.all([
		createRoleAgent(advocate, cwd),
		createRoleAgent(devil, cwd),
	]);

	const [advocateResult, devilResult] = await Promise.all([
		runAgent(advocateSession, "advocate", topic),
		runAgent(devilSession, "devil", topic),
	]);

	advocateSession.dispose();
	devilSession.dispose();

	console.log("\x1b[36m[Advocate]\x1b[0m");
	console.log(advocateResult.output.slice(0, 300) + "...\n");
	console.log("\x1b[35m[Devil's Advocate]\x1b[0m");
	console.log(devilResult.output.slice(0, 300) + "...\n");

	// Judge synthesizes
	console.log("\x1b[33m▶ Judge deliberating...\x1b[0m\n");

	const judgeSession = await createRoleAgent(judge, cwd);
	const verdict = await runAgent(
		judgeSession,
		"judge",
		`Topic: ${topic}

## Argument FOR
${advocateResult.output}

## Argument AGAINST
${devilResult.output}

Deliver your verdict.`,
	);
	judgeSession.dispose();

	return { advocate: advocateResult, devil: devilResult, judge: verdict };
}

// ============================================================================
// Main — Run all patterns
// ============================================================================

async function main() {
	const cwd = process.cwd();

	console.log("╔═══════════════════════════════════════════════════╗");
	console.log("║       Multi-Agent Orchestration Examples          ║");
	console.log("╚═══════════════════════════════════════════════════╝");
	console.log(`\nWorking directory: ${cwd}`);

	// --- Pattern 1: Sequential Pipeline ---
	const pipeline = await sequentialPipeline(cwd);

	// --- Pattern 2: Parallel Fan-Out ---
	const merged = await parallelFanOut(cwd);

	// --- Pattern 3: Coordinator ---
	const coordinated = await coordinatorPattern(cwd);

	// --- Pattern 4: Debate ---
	const debate = await debatePattern(cwd);

	// ============================================================================
	// Final Summary
	// ============================================================================

	console.log("\n═══════════════════════════════════════════════════");
	console.log("  Summary");
	console.log("═══════════════════════════════════════════════════\n");

	console.log("Pattern 1 (Sequential Pipeline):");
	console.log(`  Scout:     ${pipeline.scout.success ? "✓" : "✗"} (${pipeline.scout.output.length} chars)`);
	console.log(`  Planner:   ${pipeline.planner.success ? "✓" : "✗"} (${pipeline.planner.output.length} chars)`);
	console.log(`  Coder:     ${pipeline.coder.success ? "✓" : "✗"} (${pipeline.coder.output.length} chars)`);
	console.log(`  Reviewer:  ${pipeline.reviewer.success ? "✓" : "✗"} (${pipeline.reviewer.output.length} chars)`);

	console.log("\nPattern 2 (Parallel Fan-Out):");
	console.log(`  Merged findings: ${merged.length} chars`);

	console.log("\nPattern 3 (Coordinator):");
	for (const r of coordinated) {
		console.log(`  ${r.role}: ${r.success ? "✓" : "✗"} (${r.output.length} chars)`);
	}

	console.log("\nPattern 4 (Debate):");
	console.log(`  Advocate:    ${debate.advocate.success ? "✓" : "✗"}`);
	console.log(`  Devil:       ${debate.devil.success ? "✓" : "✗"}`);
	console.log(`  Judge:       ${debate.judge.success ? "✓" : "✗"}`);

	console.log("\nDone. All sessions disposed automatically.");
}

main().catch((err) => {
	console.error(err);
	process.exit(1);
});

