/**
 * Orchestrator Extension
 *
 * Turns pi into a pure orchestrator that never touches files directly.
 * Every task is delegated to specialist subagents with isolated contexts.
 * The main agent only holds plans and summaries — never implementation details.
 *
 * Subagents run IN-PROCESS using blank-slate ResourceLoaders (no subprocesses).
 * Isolation is by design — each subagent gets an empty ResourceLoader that
 * loads zero extensions, zero skills, zero AGENTS.md files.
 *
 * Install:
 *   ln -s "$(pwd)/orchestrator.ts" ~/.pi/agent/extensions/orchestrator.ts
 *
 * How it works:
 *   1. System prompt tells the agent to ALWAYS delegate
 *   2. registerTool() adds delegate/parallel/chain tools
 *   3. Each subagent is an in-process AgentSession with a blank ResourceLoader
 *   4. Main agent receives only compressed output
 *   5. Context stays small — only plans and summaries live here
 */

import { getModel } from "@earendil-works/pi-ai";
import {
	AuthStorage,
	createAgentSession,
	createExtensionRuntime,
	type ExtensionAPI,
	type ResourceLoader,
	SessionManager,
} from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

// ============================================================================
// Config
// ============================================================================

const MAX_PARALLEL = 4;
const OUTPUT_CAP = 30_000; // bytes per subagent output fed back to main

// ============================================================================
// Subagent definitions — each specialist has a focused prompt
// ============================================================================

interface Specialist {
	name: string;
	tools: string[];
	model?: string;
	systemPrompt: string;
}

const SPECIALISTS: Record<string, Specialist> = {
	scout: {
		name: "scout",
		tools: ["read", "bash"],
		model: "anthropic/claude-haiku-4-5",
		systemPrompt: `You are a fast codebase scout. Investigate and return compressed findings.

Rules:
- Use grep/find to locate code, read key sections only
- Output structured findings another agent can use without re-reading files
- Be concise — your output feeds into a planner

Output format:
## Files Found
(path + line ranges + what's there)

## Key Code
Critical types/functions/interfaces

## Dependencies
How pieces connect

## Recommendation
Which file to start with and why`,
	},

	coder: {
		name: "coder",
		tools: ["read", "bash", "edit", "write"],
		systemPrompt: `You are an implementation specialist. Execute a plan precisely.

Rules:
- Read files mentioned in the plan
- Make exactly the changes described — no extra changes
- Verify changes compile/run
- Report what changed

Output format:
## Completed
What was done.

## Files Changed
- path - what changed

## Verification
What you checked.`,
	},

	reviewer: {
		name: "reviewer",
		tools: ["read", "bash"],
		systemPrompt: `You are a senior code reviewer. Analyze for bugs, security, quality.

Rules:
- Read the changed files
- Check for bugs, security issues, code smells
- Be specific with file paths and line numbers
- Do NOT make changes — only report

Output format:
## Critical (must fix)
Issues that block.

## Warnings (should fix)
Issues to address.

## Suggestions (nice to have)
Improvements.

## Summary
Overall assessment in 2-3 sentences.`,
	},

	researcher: {
		name: "researcher",
		tools: ["read", "bash"],
		systemPrompt: `You are a research specialist. Investigate questions, find answers.

Rules:
- Read documentation, configs, source code
- Trace code paths to understand behavior
- Provide evidence-based answers
- Be thorough but concise

Output format:
## Answer
Direct answer to the question.

## Evidence
Code references and reasoning.

## Caveats
Limitations or edge cases.`,
	},

	writer: {
		name: "writer",
		tools: ["read", "write", "edit"],
		systemPrompt: `You are a documentation writer. Create or update docs, READMEs, comments.

Rules:
- Read existing docs to understand style
- Match the project's existing documentation patterns
- Write clearly and concisely
- Include code examples where helpful

Output format:
## Changes Made
- file: what was written/updated

## Content
The actual documentation changes.`,
	},
};

// ============================================================================
// Blank ResourceLoader — the key to in-process isolation
//
// This is a ResourceLoader that returns nothing for everything.
// No extensions, no skills, no AGENTS.md, no prompt templates.
// Each subagent gets this instead of DefaultResourceLoader,
// so it's a clean shell with only its specialist system prompt.
// ============================================================================

function createBlankLoader(specialistPrompt: string): ResourceLoader {
	return {
		getExtensions: () => ({ extensions: [], errors: [], runtime: createExtensionRuntime() }),
		getSkills: () => ({ skills: [], diagnostics: [] }),
		getPrompts: () => ({ prompts: [], diagnostics: [] }),
		getThemes: () => ({ themes: [], diagnostics: [] }),
		getAgentsFiles: () => ({ agentsFiles: [] }),
		getSystemPrompt: () => specialistPrompt,
		getAppendSystemPrompt: () => [],
		extendResources: () => {},
		reload: async () => {},
	};
}

// ============================================================================
// In-process subagent runner
// ============================================================================

async function runSubagent(
	specialist: Specialist,
	task: string,
	cwd: string,
): Promise<{ output: string; turns: number }> {
	const authStorage = AuthStorage.create();
	const modelRegistry = ModelRegistry.inMemory(authStorage);

	// Resolve model
	let model;
	if (specialist.model) {
		const [provider, id] = specialist.model.split("/");
		model = getModel(provider, id);
	}

	// Blank-slate loader — no extensions, no skills, no context files
	const loader = createBlankLoader(specialist.systemPrompt);

	const { session } = await createAgentSession({
		cwd,
		model,
		tools: specialist.tools,
		resourceLoader: loader,
		sessionManager: SessionManager.inMemory(cwd),
		authStorage,
		modelRegistry,
	});

	let output = "";
	let turns = 0;

	const unsubscribe = session.subscribe((event) => {
		if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
			output += event.assistantMessageEvent.delta;
		}
		if (event.type === "message_end" && event.message?.role === "assistant") {
			turns++;
		}
	});

	try {
		await session.prompt(task);
	} catch (error) {
		output = `[error] ${error instanceof Error ? error.message : String(error)}`;
	} finally {
		unsubscribe();
		session.dispose();
	}

	// Cap output
	if (output.length > OUTPUT_CAP) {
		output = output.slice(0, OUTPUT_CAP) + "\n\n[output truncated]";
	}

	return { output: output || "(no output)", turns };
}

// ============================================================================
// Parallel runner
// ============================================================================

async function runParallel(
	tasks: Array<{ specialist: Specialist; task: string }>,
	cwd: string,
): Promise<Array<{ specialist: string; output: string; error?: string }>> {
	const concurrency = Math.min(MAX_PARALLEL, tasks.length);
	const results: Array<{ specialist: string; output: string; error?: string }> = new Array(tasks.length);
	let nextIndex = 0;

	const workers = Array(concurrency).fill(null).map(async () => {
		while (nextIndex < tasks.length) {
			const i = nextIndex++;
			const { specialist, task } = tasks[i];
			try {
				const result = await runSubagent(specialist, task, cwd);
				results[i] = { specialist: specialist.name, output: result.output };
			} catch (error) {
				results[i] = {
					specialist: specialist.name,
					output: "",
					error: error instanceof Error ? error.message : String(error),
				};
			}
		}
	});

	await Promise.all(workers);
	return results;
}

// ============================================================================
// The Extension
// ============================================================================

export default function (pi: ExtensionAPI) {

	// ── System Prompt: Tell the agent to ALWAYS delegate ──────────────────

	pi.on("before_agent_start", async (event, _ctx) => {
		const delegationInstructions = `
## Orchestrator Mode — ALWAYS DELEGATE

You are an orchestrator. You NEVER do the work yourself. You plan and delegate.

### Rules:
1. **NEVER read files directly** — delegate to a subagent
2. **NEVER run bash commands** — delegate to a subagent
3. **NEVER write/edit files** — delegate to a subagent
4. **ALWAYS break tasks into subtasks** before delegating
5. **ALWAYS synthesize** subagent outputs into a coherent response

### Specialist roster:
- **scout** — Fast codebase investigation (read-only, haiku)
- **coder** — Implementation (read/write/bash)
- **reviewer** — Code review (read-only, thorough)
- **researcher** — Question answering (read-only)
- **writer** — Documentation (read/write)

### Tools:
- \`delegate(specialist, task)\` — single specialist
- \`parallel(tasks)\` — multiple specialists simultaneously
- \`chain(steps)\` — sequential with {previous} placeholder

### Workflow for every task:
1. Analyze the request
2. Break into subtasks
3. Delegate with the right tool
4. Synthesize results into a final answer

### Example:
User: "Add error handling to main.ts"
You: delegate(scout, "Find main.ts and understand current error handling") →
     delegate(coder, "Add try/catch based on this: {scout output}") →
     delegate(reviewer, "Review changes: {coder output}")

Your response should be the synthesized summary — NOT the implementation details.
`;

		return {
			systemPrompt: event.systemPrompt + "\n" + delegationInstructions,
		};
	});

	// ── Tool: delegate — Single task to one specialist ────────────────────

	pi.registerTool({
		name: "delegate",
		label: "Delegate Task",
		description: `Delegate a task to a specialist subagent. Runs in an isolated in-process session with its own system prompt and tools. Returns the subagent's output.`,
		parameters: Type.Object({
			specialist: Type.String({
				description: "Which specialist to use: scout, coder, reviewer, researcher, writer",
			}),
			task: Type.String({
				description: "The task to delegate. Be specific and include all necessary context.",
			}),
		}),
		async execute(toolCallId, params, signal, onUpdate) {
			const specialist = SPECIALISTS[params.specialist];
			if (!specialist) {
				const available = Object.keys(SPECIALISTS).join(", ");
				return {
					content: [{ type: "text", text: `Unknown specialist: "${params.specialist}". Available: ${available}` }],
					details: {},
				};
			}

			// Stream progress
			onUpdate?.({
				content: [{ type: "text", text: `[${specialist.name}] Starting...` }],
				details: { specialist: specialist.name, task: params.task, status: "running" },
			});

			const result = await runSubagent(specialist, params.task, ctx.cwd);

			const header = `[${specialist.name}] completed (${result.turns} turns)`;

			return {
				content: [{ type: "text", text: `${header}\n\n${result.output}` }],
				details: {
					specialist: specialist.name,
					task: params.task,
					status: "done",
					turns: result.turns,
					outputLength: result.output.length,
				},
			};
		},
	});

	// ── Tool: parallel — Multiple tasks simultaneously ────────────────────

	pi.registerTool({
		name: "parallel",
		label: "Parallel Delegation",
		description: `Delegate multiple tasks to specialists in parallel. Each runs in its own isolated in-process session. Use for independent subtasks.`,
		parameters: Type.Object({
			tasks: Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name: scout, coder, reviewer, researcher, writer" }),
					task: Type.String({ description: "Task description" }),
				}),
				{ description: "Tasks to run in parallel (max 4)" },
			),
		}),
		async execute(toolCallId, params, signal, onUpdate) {
			if (params.tasks.length > MAX_PARALLEL) {
				return {
					content: [{ type: "text", text: `Too many tasks (${params.tasks.length}). Max: ${MAX_PARALLEL}` }],
					details: {},
				};
			}

			const resolved = params.tasks
				.map((t) => {
					const spec = SPECIALISTS[t.specialist];
					if (!spec) return null;
					return { specialist: spec, task: t.task };
				})
				.filter(Boolean) as Array<{ specialist: Specialist; task: string }>;

			if (resolved.length === 0) {
				return {
					content: [{ type: "text", text: "No valid specialists found." }],
					details: {},
				};
			}

			onUpdate?.({
				content: [{ type: "text", text: `Running ${resolved.length} tasks in parallel...` }],
				details: { status: "running", count: resolved.length },
			});

			const results = await runParallel(resolved, ctx.cwd);

			const output = results
				.map((r) => {
					const status = r.error ? "ERROR" : "OK";
					return `### [${r.specialist}] ${status}\n\n${r.output}`;
				})
				.join("\n\n---\n\n");

			return {
				content: [{ type: "text", text: output }],
				details: {
					status: "done",
					results: results.map((r) => ({
						specialist: r.specialist,
						outputLength: r.output.length,
						error: r.error,
					})),
				},
			};
		},
	});

	// ── Tool: chain — Sequential pipeline with context passing ────────────

	pi.registerTool({
		name: "chain",
		label: "Chain Delegation",
		description: `Run specialists sequentially, passing each output to the next. Use {previous} placeholder in task text to reference prior output.`,
		parameters: Type.Object({
			steps: Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name" }),
					task: Type.String({
						description: "Task text. Use {previous} to insert prior step output.",
					}),
				}),
				{ description: "Steps to run in order" },
			),
		}),
		async execute(toolCallId, params, signal, onUpdate) {
			const results: Array<{ step: number; specialist: string; output: string; error?: string }> = [];
			let previousOutput = "";

			for (let i = 0; i < params.steps.length; i++) {
				const step = params.steps[i];
				const specialist = SPECIALISTS[step.specialist];

				if (!specialist) {
					results.push({
						step: i + 1,
						specialist: step.specialist,
						output: "",
						error: `Unknown specialist: "${step.specialist}"`,
					});
					break;
				}

				const task = step.task.replace(/\{previous\}/g, previousOutput);

				onUpdate?.({
					content: [{ type: "text", text: `Step ${i + 1}/${params.steps.length}: [${specialist.name}] running...` }],
					details: {
						status: "running",
						step: i + 1,
						total: params.steps.length,
						specialist: specialist.name,
					},
				});

				const result = await runSubagent(specialist, task, ctx.cwd);
				previousOutput = result.output;

				results.push({
					step: i + 1,
					specialist: specialist.name,
					output: result.output,
				});

				// Stop chain on error output
				if (result.output.startsWith("[error]")) break;
			}

			const output = results
				.map((r) => {
					const status = r.error ? "ERROR" : "OK";
					return `### Step ${r.step}: [${r.specialist}] ${status}\n\n${r.output}`;
				})
				.join("\n\n---\n\n");

			return {
				content: [{ type: "text", text: output }],
				details: { status: "done", steps: results.length, results },
			};
		},
	});

	// ── Command: /orchestrate — Quick delegation from user ─────────────────

	pi.registerCommand("orchestrate", {
		description: "Delegate a task to the orchestrator (scout → plan → implement → review)",
		handler: async (args, ctx) => {
			if (!args.trim()) {
				ctx.ui.notify("Usage: /orchestrate <task description>", "warning");
				return;
			}

			pi.sendUserMessage(
				`Orchestrate this task by delegating to specialists:\n\n${args}\n\nUse the chain tool: scout → coder → reviewer. Synthesize the final result.`,
			);
		},
	});

	// ── Command: /delegates — Show available specialists ───────────────────

	pi.registerCommand("delegates", {
		description: "List available specialist subagents",
		handler: async (_args, ctx) => {
			const lines = Object.values(SPECIALISTS).map(
				(s) => `  ${s.name.padEnd(12)} tools: ${s.tools.join(", ")}${s.model ? `  model: ${s.model}` : ""}`,
			);
			ctx.ui.notify(`Specialists:\n${lines.join("\n")}`, "info");
		},
	});
}

