/**
 * Orchestrator Extension
 *
 * Turns pi into a pure orchestrator that never touches files directly.
 * Every task is delegated to specialist subagents with isolated contexts.
 * The main agent only holds plans and summaries — never implementation details.
 *
 * Subagents run IN-PROCESS using blank-slate ResourceLoaders (no subprocesses).
 * Isolation is by design — each subagent gets an empty ResourceLoader that
 * loads zero extensions, zero skills, zero AGENTS.md files.
 *
 * Install:
 *   ln -s "$(pwd)/orchestrator.ts" ~/.pi/agent/extensions/orchestrator.ts
 *
 * How it works:
 *   1. System prompt tells the agent to ALWAYS delegate
 *   2. registerTool() adds delegate/parallel/chain tools
 *   3. Each subagent is an in-process AgentSession with a blank ResourceLoader
 *   4. Main agent receives only compressed output
 *   5. Context stays small — only plans and summaries live here
 */

import { getModel } from "@earendil-works/pi-ai";
import {
	AuthStorage,
	createAgentSession,
	createExtensionRuntime,
	type ExtensionAPI,
	ModelRegistry,
	type ResourceLoader,
	SessionManager,
} from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

// ============================================================================
// Config
// ============================================================================

const MAX_PARALLEL = 4;
const OUTPUT_CAP = 30_000; // bytes per subagent output fed back to main

// ============================================================================
// Compression — applied to ALL subagent output before returning to main agent
// ============================================================================

const ANSI_RE = /\x1b\[[0-9;]*[a-zA-Z]/g;

function compressOutput(output: string): string {
	let result = output;

	// Strip ANSI color codes
	result = result.replace(ANSI_RE, "");

	// Collapse triple+ blank lines
	result = result.replace(/\n{3,}/g, "\n\n");

	// Trim leading/trailing whitespace
	result = result.trim();

	return result;
}

// ============================================================================
// Subagent definitions — each specialist has a focused prompt
// ============================================================================

interface Specialist {
	name: string;
	tools: string[];
	model?: string;
	systemPrompt: string;
}

const SPECIALISTS: Record<string, Specialist> = {
	scout: {
		name: "scout",
		tools: ["read", "bash"],
		model: "anthropic/claude-haiku-4-5",
		systemPrompt: `You are a fast codebase scout. Investigate and return compressed findings.

Rules:
- Use grep/find to locate code, read key sections only
- Output structured findings another agent can use without re-reading files
- Be concise — your output feeds into a planner
- Reply in terse fragments. No filler, no hedging, no paragraphs

Output format:
## Files Found
(path + line ranges + what's there)

## Key Code
Critical types/functions/interfaces

## Dependencies
How pieces connect

## Recommendation
Which file to start with and why`,
	},

	coder: {
		name: "coder",
		tools: ["read", "bash", "edit", "write"],
		systemPrompt: `You are an implementation specialist. Execute a plan precisely.

Rules:
- Read files mentioned in the plan
- Make exactly the changes described — no extra changes
- Verify changes compile/run
- Report what changed
- Reply in terse fragments. No filler

Output format:
## Completed
What was done.

## Files Changed
- path - what changed

## Verification
What you checked.`,
	},

	reviewer: {
		name: "reviewer",
		tools: ["read", "bash"],
		systemPrompt: `You are a senior code reviewer. Analyze for bugs, security, quality.

Rules:
- Read the changed files
- Check for bugs, security issues, code smells
- Be specific with file paths and line numbers
- Do NOT make changes — only report
- Reply in terse fragments. No filler

Output format:
## Critical (must fix)
Issues that block.

## Warnings (should fix)
Issues to address.

## Suggestions (nice to have)
Improvements.

## Summary
Overall assessment in 2-3 sentences.`,
	},

	researcher: {
		name: "researcher",
		tools: ["read", "bash"],
		systemPrompt: `You are a research specialist. Investigate questions, find answers.

Rules:
- Read documentation, configs, source code
- Trace code paths to understand behavior
- Provide evidence-based answers
- Be thorough but concise
- Reply in terse fragments. No filler

Output format:
## Answer
Direct answer to the question.

## Evidence
Code references and reasoning.

## Caveats
Limitations or edge cases.`,
	},

	writer: {
		name: "writer",
		tools: ["read", "write", "edit"],
		systemPrompt: `You are a documentation writer. Create or update docs, READMEs, comments.

Rules:
- Read existing docs to understand style
- Match the project's existing documentation patterns
- Write clearly and concisely
- Include code examples where helpful
- Reply in terse fragments. No filler

Output format:
## Changes Made
- file: what was written/updated

## Content
The actual documentation changes.`,
	},
};

// ============================================================================
// Blank ResourceLoader — the key to in-process isolation
//
// This is a ResourceLoader that returns nothing for everything.
// No extensions, no skills, no AGENTS.md, no prompt templates.
// Each subagent gets this instead of DefaultResourceLoader,
// so it's a clean shell with only its specialist system prompt.
// ============================================================================

function createBlankLoader(specialistPrompt: string): ResourceLoader {
	return {
		getExtensions: () => ({ extensions: [], errors: [], runtime: createExtensionRuntime() }),
		getSkills: () => ({ skills: [], diagnostics: [] }),
		getPrompts: () => ({ prompts: [], diagnostics: [] }),
		getThemes: () => ({ themes: [], diagnostics: [] }),
		getAgentsFiles: () => ({ agentsFiles: [] }),
		getSystemPrompt: () => specialistPrompt,
		getAppendSystemPrompt: () => [],
		extendResources: () => {},
		reload: async () => {},
	};
}

// ============================================================================
// In-process subagent runner
// ============================================================================

async function runSubagent(
	specialist: Specialist,
	task: string,
	cwd: string,
): Promise<{ output: string; turns: number }> {
	const authStorage = AuthStorage.create();
	const modelRegistry = ModelRegistry.inMemory(authStorage);

	// Resolve model
	let model;
	if (specialist.model) {
		const [provider, id] = specialist.model.split("/");
		model = getModel(provider, id);
	}

	// Blank-slate loader — no extensions, no skills, no context files
	const loader = createBlankLoader(specialist.systemPrompt);

	const { session } = await createAgentSession({
		cwd,
		model,
		tools: specialist.tools,
		resourceLoader: loader,
		sessionManager: SessionManager.inMemory(cwd),
		authStorage,
		modelRegistry,
	});

	let output = "";
	let turns = 0;

	const unsubscribe = session.subscribe((event) => {
		if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
			output += event.assistantMessageEvent.delta;
		}
		if (event.type === "message_end" && event.message?.role === "assistant") {
			turns++;
		}
	});

	try {
		await session.prompt(task);
	} catch (error) {
		output = `[error] ${error instanceof Error ? error.message : String(error)}`;
	} finally {
		unsubscribe();
		session.dispose();
	}

	// Compress + cap output before returning to main agent
	let finalOutput = compressOutput(output || "(no output)");
	if (finalOutput.length > OUTPUT_CAP) {
		finalOutput = finalOutput.slice(0, OUTPUT_CAP) + "\n\n[output truncated]";
	}

	return { output: finalOutput, turns };
}

