/**
 * Lint Hook — Deterministic linting after every file change
 *
 * Automatically runs the project's linter/type-checker after every
 * edit or write tool call. The agent never forgets — it's automatic.
 *
 * Detects: biome, eslint, tsc, bun check, deno check
 * Runs via tool_result hook — zero agent intervention needed.
 *
 * Install:
 *   ln -s "$(pwd)/lint-hook.ts" ~/.pi/agent/extensions/lint-hook.ts
 */

import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

// ============================================================================
// Linter detection — find what the project uses
// ============================================================================

interface LinterCommand {
	name: string;
	command: string;
}

function detectLinter(cwd: string): LinterCommand | null {
	const fs = require("node:fs");
	const path = require("node:path");

	//

/**
 * Lint Guard — Deterministic lint checking for every file change
 *
 * Two modes:
 *   1. Auto-lint: hooks into tool_result after edit/write, runs linter automatically
 *   2. Manual lint: registers a `lint` tool the agent can call explicitly
 *
 * Auto-detects linter from project config:
 *   - biome.json → biome check
 *   - .eslintrc* / eslint.config.* → eslint
 *   - tsconfig.json → tsc --noEmit
 *   - package.json scripts → npm run check / npm run lint
 *
 * Install:
 *   ln -s "$(pwd)/lint-guard.ts" ~/.pi/agent/extensions/lint-guard.ts
 */

import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

// ============================================================================
// Linter detection
// ============================================================================

interface LinterConfig {
	name: string;
	command: string;
	args: string[];
	/** File patterns to check (glob) */
	patterns: string[];
}

function detectLinter(cwd: string): LinterConfig | null {
	// 1. Biome
	if (existsSync(join(cwd, "biome.json")) || existsSync(join(cwd, "biome.jsonc"))) {
		return {
			name: "biome",
			command: "npx",
			args: ["biome", "check", "--no-errors-on-unmatched"],
			patterns: ["**/*.{ts,tsx,js,jsx,json}"],
		};
	}

	// 2. ESLint
	const eslintConfigs = [
		"eslint.config.js",
		"eslint.config.mjs",
		"eslint.config.ts",
		".eslintrc.js",
		".eslintrc.mjs",
		".eslintrc.json",
		".eslintrc.yml",
	];
	if (eslintConfigs.some((c) => existsSync(join(cwd, c)))) {
		return {
			name: "eslint",
			command: "npx",
			args: ["eslint", "--no-error-on-unmatched-pattern"],
			patterns: ["**/*.{ts,tsx,js,jsx}"],
		};
	}

	// 3. TypeScript
	if (existsSync(join(cwd, "tsconfig.json"))) {
		return {
			name: "tsc",
			command: "npx",
			args: ["tsc", "--noEmit", "--pretty", "false"],
			patterns: ["**/*.ts"],
		};
	}

	// 4. Package.json scripts
	if (existsSync(join(cwd, "package.json"))) {
		try {
			const pkg = JSON.parse(readFileSync(join(cwd, "package.json"), "utf-8"));
			const scripts = pkg.scripts || {};

			if (scripts.check) {
				return {
					name: "npm-check",
					command: "npm",
					args: ["run", "check"],
					patterns: [],
				};
			}
			if (scripts.lint) {
				return {
					name: "npm-lint",
					command: "npm",
					args: ["run", "lint"],
					patterns: [],
				};
			}
		} catch {
			// ignore parse errors
		}
	}

	return null;
}

// ============================================================================
// Linter runner
// ============================================================================

interface LintResult {
	linter: string;
	success: boolean;
	errors: string;
	/** Files that were checked */
	filesChecked: string[];
}

async function runLinter(
	cwd: string,
	filePaths?: string[],
): Promise<LintResult> {
	const config = detectLinter(cwd);

	if (!config) {
		return {
			linter: "none",
			success: true,
			errors: "No linter found in project (checked: biome.json, .eslintrc*, tsconfig.json, package.json scripts.check)",
			filesChecked: [],
		};
	}

	const args = [...config.args];
	if (filePaths && filePaths.length > 0 && config.patterns.length > 0) {
		// Only lint changed files
		args.push(...filePaths);
	}

	return new Promise((resolve) => {
		const { spawn } = require("node:child_process");
		const proc = spawn(config.command, args, {
			cwd,
			shell: false,
			stdio: ["ignore", "pipe", "pipe"],
		});

		let stdout = "";
		let stderr = "";

		proc.stdout.on("data", (data: Buffer) => {
			stdout += data.toString();
		});

		proc.stderr.on("data", (data: Buffer) => {
			stderr += data.toString();
		});

		proc.on("close", (code: number | null) => {
			const output = (stdout + stderr).trim();

			// Cap output at 5000 chars
			const capped = output.length > 5000
				? output.slice(0, 5000) + "\n\n[output truncated]"
				: output;

			resolve({
				linter: config.name,
				success: code === 0,
				errors: capped || (code === 0 ? "No issues found" : "Unknown error"),
				filesChecked: filePaths || [],
			});
		});

		proc.on("error", () => {
			resolve({
				linter: config.name,
				success: false,
				errors: `Failed to run ${config.command} ${config.args.join(" ")}`,
				filesChecked: [],
			});
		});
	});
}

// ============================================================================
// State
// ============================================================================

let autoLint = true;
let lastEditedFiles: string[] = [];

// ============================================================================
// The Extension
// ============================================================================

export default function (pi: ExtensionAPI) {

	// ── Auto-lint after edit/write ────────────────────────────────────────

	pi.on("tool_result", async (event) => {
		if (!autoLint) return;

		// Track edited files
		if (event.toolName === "edit" || event.toolName === "write") {
			const path = (event.input as Record<string, unknown>)?.path
				|| (event.input as Record<string, unknown>)?.file_path;
			if (path && typeof path === "string") {
				lastEditedFiles.push(path);
			}
		}

		// After edit/write, run linter on changed files
		if (event.toolName === "edit" || event.toolName === "write") {
			// Only lint if we have tracked files
			if (lastEditedFiles.length === 0) return;

			const files = [...lastEditedFiles];
			lastEditedFiles = [];

			const result = await runLinter(ctx.cwd, files);

			if (!result.success) {
				// Append lint errors to the tool result
				const lintMsg = `\n\n--- Lint (${result.linter}) ---\n${result.errors}`;
				const currentText = event.content
					.filter((c): c is { type: "text"; text: string } => c.type === "text")
					.map((c) => c.text)
					.join("\n");

				return {
					content: [{ type: "text", text: currentText + lintMsg }],
				};
			}
		}
	});

	// ── Tool: lint — Manual lint check ────────────────────────────────────

	pi.registerTool({
		name: "lint",
		label: "Lint Check",
		description: `Run linter on files. Auto-detects biome/eslint/tsc. Use after making changes to verify code quality.`,
		parameters: Type.Object({
			files: Type.Optional(Type.Array(
				Type.String({ description: "File paths to lint (relative to cwd)" }),
				{ description: "Specific files to lint. Empty = lint whole project." },
			)),
		}),
		async execute(toolCallId, params, signal, onUpdate, ctx) {
			onUpdate?.({
				content: [{ type: "text", text: "Running linter..." }],
				details: { status: "running" },
			});

			const result = await runLinter(ctx.cwd, params.files);

			const icon = result.success ? "✓" : "✗";
			const header = `[${result.linter}] ${icon} ${result.success ? "passed" : "failed"}`;
			const files = result.filesChecked.length > 0
				? `\nFiles: ${result.filesChecked.join(", ")}`
				: "";

			return {
				content: [{ type: "text", text: `${header}${files}\n\n${result.errors}` }],
				details: {
					linter: result.linter,
					success: result.success,
					filesChecked: result.filesChecked,
				},
				isError: !result.success,
			};
		},
	});

	// ── Tool: typecheck — TypeScript only ─────────────────────────────────

	pi.registerTool({
		name: "typecheck",
		label: "Type Check",
		description: `Run TypeScript type checking (tsc --noEmit). Use after code changes to verify types.`,
		parameters: Type.Object({}),
		async execute(toolCallId, params, signal, onUpdate, ctx) {
			onUpdate?.({
				content: [{ type: "text", text: "Running tsc --noEmit..." }],
				details: { status: "running" },
			});

			return new Promise((resolve) => {
				const { spawn } = require("node:child_process");
				const proc = spawn("npx", ["tsc", "--noEmit", "--pretty", "false"], {
					cwd: ctx.cwd,
					shell: false,
					stdio: ["ignore", "pipe", "pipe"],
				});

				let stdout = "";
				let stderr = "";

				proc.stdout.on("data", (data: Buffer) => { stdout += data.toString(); });
				proc.stderr.on("data", (data: Buffer) => { stderr += data.toString(); });

				proc.on("close", (code: number | null) => {
					const output = (stdout + stderr).trim();
					const capped = output.length > 5000
						? output.slice(0, 5000) + "\n\n[output truncated]"
						: output;

					const success = code === 0;
					const header = success ? "✓ Types clean" : "✗ Type errors";

					resolve({
						content: [{ type: "text", text: `${header}\n\n${capped || "(no output)"}` }],
						details: { success, errors: capped },
						isError: !success,
					});
				});

				proc.on("error", (err: Error) => {
					resolve({
						content: [{ type: "text", text: `Failed to run tsc: ${err.message}` }],
						details: { success: false },
						isError: true,
					});
				});
			});
		},
	});

	// ── Commands ──────────────────────────────────────────────────────────

	pi.registerCommand("lint", {
		description: "Run linter on the project",
		handler: async (args, ctx) => {
			const files = args.trim() ? args.trim().split(/\s+/) : undefined;
			const result = await runLinter(ctx.cwd, files);
			const icon = result.success ? "✓" : "✗";
			ctx.ui.notify(
				`[${result.linter}] ${icon} ${result.success ? "passed" : "failed"}\n${result.errors.slice(0, 500)}`,
				result.success ? "info" : "error",
			);
		},
	});

	pi.registerCommand("lintguard", {
		description: "Toggle auto-lint on/off",
		handler: async (args, ctx) => {
			const arg = args.trim().toLowerCase();
			if (arg === "on") autoLint = true;
			else if (arg === "off") autoLint = false;
			else autoLint = !autoLint;

			ctx.ui.notify(
				`Auto-lint: ${autoLint ? "ON" : "OFF"}\n` +
				`Linter: ${detectLinter(ctx.cwd)?.name || "none detected"}`,
				"info",
			);
		},
	});
}

