content.text:
/**
 * Lint Guard — Deterministic lint checking for every file change
 *
 * Two modes:
 *   1. Auto-lint: hooks into tool_result after edit/write, runs linter automatically
 *   2. Manual lint: registers a `lint` tool the agent can call explicitly
 *
 * Auto-detects linter from project config:
 *   - biome.json → biome check
 *   - .eslintrc* / eslint.config.* → eslint
 *   - tsconfig.json → tsc --noEmit
 *   - package.json scripts → npm run check / npm run lint
 *
 * Install:
 *   ln -s "$(pwd)/lint-guard.ts" ~/.pi/agent/extensions/lint-guard.ts
 */

import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

// ============================================================================
// Linter detection
// ============================================================================

interface LinterConfig {
	name: string;
	command: string;
	args: string[];
	/** File patterns to check (glob) */
	patterns: string[];
}

function detectLinter(cwd: string): LinterConfig | null {
	// ── TypeScript / JavaScript ──

	// 1. Biome
	if (existsSync(join(cwd, "biome.json")) || existsSync(join(cwd, "biome.jsonc"))) {
		return {
			name: "biome",
			command: "npx",
			args: ["biome", "check", "--no-errors-on-unmatched"],
			patterns: ["**/*.{ts,tsx,js,jsx,json}"],
		};
	}

	// 2. ESLint
	const eslintConfigs = [
		"eslint.config.js",
		"eslint.config.mjs",
		"eslint.config.ts",
		".eslintrc.js",
		".eslintrc.mjs",
		".eslintrc.json",
		".eslintrc.yml",
	];
	if (eslintConfigs.some((c) => existsSync(join(cwd, c)))) {
		return {
			name: "eslint",
			command: "npx",
			args: ["eslint", "--no-error-on-unmatched-pattern"],
			patterns: ["**/*.{ts,tsx,js,jsx}"],
		};
	}

	// 3. TypeScript
	if (existsSync(join(cwd, "tsconfig.json"))) {
		return {
			name: "tsc",
			command: "npx",
			args: ["tsc", "--noEmit", "--pretty", "false"],
			patterns: ["**/*.ts"],
		};
	}

	// ── Python ──

	// 4. Ruff (fast, modern Python linter)
	if (existsSync(join(cwd, "ruff.toml")) || existsSync(join(cwd, "pyproject.toml"))) {
		const hasRuff = existsSync(join(cwd, "ruff.toml"));
		// Check pyproject.toml for [tool.ruff]
		if (!hasRuff && existsSync(join(cwd, "pyproject.toml"))) {
			try {
				const pyproject = readFileSync(join(cwd, "pyproject.toml"), "utf-8");
				if (pyproject.includes("[tool.ruff]")) {
					return {
						name: "ruff",
						command: "ruff",
						args: ["check"],
						patterns: ["**/*.py"],
					};
				}
			} catch {}
		}
		if (hasRuff) {
			return {
				name: "ruff",
				command: "ruff",
				args: ["check"],
				patterns: ["**/*.py"],
			};
		}
	}

	// 5. mypy (type checker)
	if (existsSync(join(cwd, "mypy.ini")) || existsSync(join(cwd, ".mypy.ini"))) {
		return {
			name: "mypy",
			command: "mypy",
			args: ["."],
			patterns: ["**/*.py"],
		};
	}

	// 6. pyproject.toml with [tool.mypy]
	if (existsSync(join(cwd, "pyproject.toml"))) {
		try {
			const pyproject = readFileSync(join(cwd, "pyproject.toml"), "utf-8");
			if (pyproject.includes("[tool.mypy]")) {
				return {
					name: "mypy",
					command: "mypy",
					args: ["."],
					patterns: ["**/*.py"],
				};
			}
		} catch {}
	}

	// 7. flake8
	if (existsSync(join(cwd, ".flake8")) || existsSync(join(cwd, "setup.cfg"))) {
		return {
			name: "flake8",
			command: "flake8",
			args: ["."],
			patterns: ["**/*.py"],
		};
	}

	// 8. pylint
	if (existsSync(join(cwd, ".pylintrc")) || existsSync(join(cwd, "pylintrc"))) {
		return {
			name: "pylint",
			command: "pylint",
			args: ["."],
			patterns: ["**/*.py"],
		};
	}

	// ── Go ──

	// 9. golangci-lint
	if (existsSync(join(cwd, ".golangci.yml")) || existsSync(join(cwd, ".golangci.yaml"))) {
		return {
			name: "golangci-lint",
			command: "golangci-lint",
			args: ["run"],
			patterns: ["**/*.go"],
		};
	}

	// 10. Go module (fallback to go vet)
	if (existsSync(join(cwd, "go.mod"))) {
		return {
			name: "go-vet",
			command: "go",
			args: ["vet", "./..."],
			patterns: ["**/*.go"],
		};
	}

	// ── Rust ──

	// 11. Clippy
	if (existsSync(join(cwd, "Cargo.toml"))) {
		return {
			name: "clippy",
			command: "cargo",
			args: ["clippy", "--", "-D", "warnings"],
			patterns: ["**/*.rs"],
		};
	}

	// ── Java ──

	// 12. Maven
	if (existsSync(join(cwd, "pom.xml"))) {
		return {
			name: "mvn",
			command: "mvn",
			args: ["compile", "-q"],
			patterns: ["**/*.java"],
		};
	}

	// 13. Gradle
	if (existsSync(join(cwd, "build.gradle")) || existsSync(join(cwd, "build.gradle.kts"))) {
		return {
			name: "gradle",
			command: "./gradlew",
			args: ["compileJava", "--quiet"],
			patterns: ["**/*.java"],
		};
	}

	// ── Ruby ──

	// 14. RuboCop
	if (existsSync(join(cwd, ".rubocop.yml"))) {
		return {
			name: "rubocop",
			command: "rubocop",
			args: [],
			patterns: ["**/*.rb"],
		};
	}

	// ── Package.json scripts (fallback for any JS/TS project) ──

	if (existsSync(join(cwd, "package.json"))) {
		try {
			const pkg = JSON.parse(readFileSync(join(cwd, "package.json"), "utf-8"));
			const scripts = pkg.scripts || {};

			if (scripts.check) {
				return {
					name: "npm-check",
