				const proc = spawn("npx", ["tsc", "--noEmit", "--pretty", "false"], {
					cwd: ctx.cwd,
					shell: false,
					stdio: ["ignore", "pipe", "pipe"],
				});

				let stdout = "";
				let stderr = "";

				proc.stdout.on("data", (data: Buffer) => { stdout += data.toString(); });
				proc.stderr.on("data", (data: Buffer) => { stderr += data.toString(); });

				proc.on("close", (code: number | null) => {
					const output = (stdout + stderr).trim();
					const capped = output.length > 5000
						? output.slice(0, 5000) + "\n\n[output truncated]"
						: output;

					const success = code === 0;
					const header = success ? "✓ Types clean" : "✗ Type errors";

					resolve({
						content: [{ type: "text", text: `${header}\n\n${capped || "(no output)"}` }],
						details: { success, errors: capped },
						isError: !success,
					});
				});

				proc.on("error", (err: Error) => {
					resolve({
						content: [{ type: "text", text: `Failed to run tsc: ${err.message}` }],
						details: { success: false },
						isError: true,
